from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Helper functions to load and save data from files

def load_auctions():
    auctions = []
    path = 'data/auctions.txt'
    if os.path.exists(path):
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 9:
                    auction = {
                        'auction_id': int(parts[0]),
                        'item_name': parts[1],
                        'description': parts[2],
                        'category': parts[3],
                        'starting_bid': float(parts[4]),
                        'current_bid': float(parts[5]),
                        'end_time': parts[6],
                        'status': parts[7],
                        'image_url': parts[8],
                    }
                    auctions.append(auction)
    return auctions


def save_auctions(auctions):
    path = 'data/auctions.txt'
    lines = []
    for a in auctions:
        line = f"{a['auction_id']}|{a['item_name']}|{a['description']}|{a['category']}|{a['starting_bid']}|{a['current_bid']}|{a['end_time']}|{a['status']}|{a['image_url']}"
        lines.append(line)
    with open(path, 'w', encoding='utf-8') as f:
        f.write('\n'.join(lines))


def load_categories():
