# Route Implementations

@app.route('/')
def root_redirect():
    return redirect(url_for('auction_dashboard'))


@app.route('/dashboard')
def auction_dashboard():
    auctions = load_auctions()
    # featured_auctions: list(dict(auction_id=int, item_name=str, current_bid=float))
    # Let's consider Featured are 3 auctions with earliest end time and active
    active_auctions = [a for a in auctions if a['status'].lower() == 'active']
    # Sort by end_time ascending
    active_auctions.sort(key=lambda x: x['end_time'])
    featured_auctions = []
    for a in active_auctions[:3]:
        featured_auctions.append({
            'auction_id': a['auction_id'],
            'item_name': a['item_name'],
            'current_bid': a['current_bid']
        })

    trending_auctions_data = load_trending()
    # trending_auctions: list(dict(auction_id=int, item_name=str, current_bid=float, bid_count=int))
    trending_auctions = []
    for entry in trending_auctions_data:
        trending_auctions.append({
            'auction_id': entry['auction_id'],
            'item_name': entry['item_name'],
            'current_bid': entry['current_bid'],
            'bid_count': entry['bid_count'],
        })

    return render_template('dashboard.html', featured_auctions=featured_auctions, trending_auctions=trending_auctions)


@app.route('/catalog')
def auction_catalog():
