@app.route('/auction/<int:auction_id>')
def auction_details(auction_id):
    auctions = load_auctions()
    auction = None
    for a in auctions:
        if a['auction_id'] == auction_id:
            auction = a
            break
    if not auction:
        return "Auction not found", 404

    bid_history_data = load_bid_history()
    bid_history = []
    for b in bid_history_data:
        if b['auction_id'] == auction_id:
            bid_history.append({
                'bidder_name': b['bidder_name'],
                'bid_amount': b['bid_amount']
            })

    return render_template('auction_details.html', auction=auction, bid_history=bid_history)


@app.route('/auction/<int:auction_id>/place_bid', methods=['GET'])
def place_bid(auction_id):
    auctions = load_auctions()
    auction = None
    for a in auctions:
        if a['auction_id'] == auction_id:
            auction = a
            break
    if not auction:
        return "Auction not found", 404

    # auction dict (auction_id:int, item_name:str, current_bid:float, minimum_bid:float)
    minimum_bid = auction['current_bid'] if auction['current_bid'] > 0 else auction['starting_bid']
    auction_info = {
        'auction_id': auction['auction_id'],
        'item_name': auction['item_name'],
        'current_bid': auction['current_bid'],
        'minimum_bid': minimum_bid
    }
    return render_template('place_bid.html', auction=auction_info)


@app.route('/auction/<int:auction_id>/place_bid', methods=['POST'])
def submit_bid(auction_id):
    bidder_name = request.form.get('bidder_name', '').strip()
    bid_amount_str = request.form.get('bid_amount', '').strip()

    if not bidder_name or not bid_amount_str:
        # Missing form data, re-render place_bid
        return place_bid(auction_id)
    try:
        bid_amount = float(bid_amount_str)
    except ValueError:
        return place_bid(auction_id)

    auctions = load_auctions()
    auction = None
    for a in auctions:
        if a['auction_id'] == auction_id:
            auction = a
            break
    if not auction:
        return "Auction not found", 404

    minimum_bid = auction['current_bid'] if auction['current_bid'] > 0 else auction['starting_bid']
    if bid_amount < minimum_bid:
        # Bid too low, re-render place_bid
        return place_bid(auction_id)

    # All good: update auction current_bid
    auction['current_bid'] = bid_amount
    # Save auctions
    save_auctions(auctions)

    # Load bids for id generation
    bids = load_bids()
    new_bid_id = 1
    if bids:
        new_bid_id = max(b['bid_id'] for b in bids) + 1

    now_str = datetime.now().strftime('%Y-%m-%d %H:%M')

    new_bid = {
        'bid_id': new_bid_id,
