@app.route('/make_reservation', methods=['GET', 'POST'])
def make_reservation():
    if request.method == 'GET':
        # Render the reservation form
        return render_template('make_reservation.html')

    # POST: process reservation form
    guest_name = request.form.get('guest_name', '').strip()
    try:
        party_size = int(request.form.get('party_size', '1'))
    except ValueError:
        party_size = 1
    reservation_date = request.form.get('reservation_date', '').strip()

    # Validate party size
    if party_size < 1 or party_size > 10:
        party_size = 1

    # Validate reservation_date (simple check YYYY-MM-DD)
    try:
        datetime.strptime(reservation_date, '%Y-%m-%d')
    except ValueError:
        # Invalid date - redirect back to make_reservation GET
        return redirect(url_for('make_reservation'))

    # Load current users to get contact info
    users = load_users()
    user = users.get(CURRENT_USER)
    if not user:
        # No user data, error fallback
        return redirect(url_for('make_reservation'))

    # Compose new reservation
    reservations = load_reservations()
    if reservations:
        new_id = max(r['reservation_id'] for r in reservations) + 1
    else:
        new_id = 1

    # Use current time for reservation time - for demo use fixed time 19:00
    reservation_time = '19:00'

    new_reservation = {
        'reservation_id': new_id,
        'username': CURRENT_USER,
        'guest_name': guest_name if guest_name else user['full_name'],
        'phone': user['phone'],
        'email': user['email'],
        'party_size': party_size,
        'date': reservation_date,
        'time': reservation_time,
        'special_requests': '',
        'status': 'Upcoming'
