@app.route('/cancel_reservation/<int:reservation_id>', methods=['POST'])
def cancel_reservation(reservation_id):
    reservations = load_reservations()
    changed = False
    for r in reservations:
        if r['reservation_id'] == reservation_id and r['username'] == CURRENT_USER and r['status'] == 'Upcoming':
            r['status'] = 'Cancelled'
            changed = True
            break
    if changed:
        save_reservations(reservations)
    return redirect(url_for('my_reservations'))


@app.route('/waitlist', methods=['GET', 'POST'])
def waitlist():
    waitlist = load_waitlist()

    # Find if current user is active in waitlist
    position = None
    if request.method == 'GET':
        # Calculate position if user in active waitlist
        active_entries = [w for w in waitlist if w['status'] == 'Active']
        # sort by join_time ascending
        active_entries.sort(key=lambda x: x['join_time'])
        for idx, entry in enumerate(active_entries, 1):
            if entry['username'] == CURRENT_USER:
                position = idx
                break

        return render_template('waitlist.html', position=position)
    else:
        # POST: join waitlist
        try:
            party_size = int(request.form.get('party_size', '1'))
        except ValueError:
            party_size = 1

        if party_size < 1:
            party_size = 1

        # Check if user already active in waitlist
        for w in waitlist:
            if w['username'] == CURRENT_USER and w['status'] == 'Active':
                # Already on waitlist, just render current position
                active_entries = [w for w in waitlist if w['status'] == 'Active']
                active_entries.sort(key=lambda x: x['join_time'])
                position = None
                for idx, entry in enumerate(active_entries, 1):
                    if entry['username'] == CURRENT_USER:
                        position = idx
                        break
                return render_template('waitlist.html', position=position)

        # Add new waitlist entry
        if waitlist:
            new_id = max(w['waitlist_id'] for w in waitlist) + 1
        else:
            new_id = 1
        now_ts = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        waitlist.append({
            'waitlist_id': new_id,
            'username': CURRENT_USER,
            'party_size': party_size,
            'join_time': now_ts,
            'status': 'Active'
        })
        save_waitlist(waitlist)

        # After joining, recalc position
        active_entries = [w for w in waitlist if w['status'] == 'Active']
        active_entries.sort(key=lambda x: x['join_time'])
        position = None
        for idx, entry in enumerate(active_entries, 1):
            if entry['username'] == CURRENT_USER:
                position = idx
                break
        return render_template('waitlist.html', position=position)


