def next_cart_id(cart_items):
    if not cart_items:
        return 1
    return max(c['cart_id'] for c in cart_items) + 1

def next_review_id(reviews):
    if not reviews:
        return 1
    return max(r['review_id'] for r in reviews) + 1

def next_order_id(orders):
    if not orders:
        return 1
    return max(o['order_id'] for o in orders) + 1

