<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Weekly Forecast</title>
</head>
<body>
    <nav>
        <a href="{{ url_for('dashboard') }}" id="back-to-dashboard">Back to Dashboard</a>
    </nav>
    <h1>Weekly Forecast for {{ location_name }}</h1>
    <table id="forecast-table">
        <thead>
            <tr>
                <th>Date</th>
                <th>High Temp</th>
                <th>Low Temp</th>
                <th>Condition</th>
                <th>Precipitation (%)</th>
                <th>Humidity (%)</th>
            </tr>
        </thead>
        <tbody>
        {% for forecast in forecasts %}
            <tr>
                <td>{{ forecast.date }}</td>
                <td>{{ forecast.high_temp }}</td>
                <td>{{ forecast.low_temp }}</td>
                <td>{{ forecast.condition }}</td>
                <td>{{ forecast.precipitation }}</td>
                <td>{{ forecast.humidity }}</td>
            </tr>
        {% endfor %}
        </tbody>
    </table>
</body>
</html>
